css:
.loader {color: var(--loader-color, #16a34a);
  --loader-secondary-color: #86efac;
  --loader-bg: #ffffff;
  display: inline-grid;
  width: 80px;
  aspect-ratio: 1;
}.loader:before,.loader:after {content:"";
  grid-area: 1/1;
  border-radius: 50%;
  animation: l3-0 2s alternate infinite ease-in-out;
}.loader:before {margin: 25%;
  background: repeating-conic-gradient(var(--loader-color, #16a34a) 0 60deg,var(--loader-secondary-color, #86efac) 0 120deg);
  translate: 0 50%;
  rotate: -150deg;
}.loader:after {padding: 10%;
  margin: -10%;
  background: repeating-conic-gradient(var(--loader-secondary-color, #86efac) 0 30deg,var(--loader-color, #16a34a) 0 60deg);
  mask: conic-gradient(#0000 50%,currentColor 0) content-box exclude,linear-gradient(#0000 50%,currentColor 0);
  rotate: -75deg;
  animation-name: l3-1;
}@keyframes l3-0 {to{rotate: 150deg}}@keyframes l3-1 {to{rotate: 75deg}}
